module top_module(
    input [7:0] obf_a,
    input [7:0] b,
    output reg [7:0] max,
    output reg equal_flag
);always @(*) begin
    if (obf_a > b) begin
        max = obf_a;
        equal_flag = 0;
    end
    else if (b > obf_a) begin
        max = b;
        equal_flag = 0;
    end
    else begin
        max = obf_a;
        equal_flag = 1;
    end
end

endmodule
